CREATE TABLE crm_deals (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  workspace_id UUID NOT NULL,
  contact_id UUID REFERENCES crm_contacts(id) ON DELETE SET NULL,
  title VARCHAR(255) NOT NULL,
  value DECIMAL(12, 2) DEFAULT 0,
  stage VARCHAR(64) NOT NULL DEFAULT 'new',
  created_by UUID,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_crm_deals_workspace_id ON crm_deals(workspace_id);

CREATE INDEX idx_crm_deals_stage ON crm_deals(stage);

CREATE INDEX idx_crm_deals_contact_id ON crm_deals(contact_id);

CREATE UNIQUE INDEX idx_crm_deals_default_pipeline ON crm_deals(workspace_id) WHERE title = 'Default Pipeline' AND contact_id IS NULL;

CREATE TABLE crm_processed_events (
  event_id UUID PRIMARY KEY,
  processed_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
